	(504,'_transient_acf_plugin_info_pro','a:19:{s:4:\"name\";s:26:\"Advanced Custom Fields PRO\";s:4:\"slug\";s:26:\"advanced-custom-fields-pro\";s:7:\"version\";s:5:\"6.6.2\";s:8:\"homepage\";s:36:\"https://www.advancedcustomfields.com\";s:6:\"author\";s:155:\"<a href=\"https://wpengine.com/?utm_source=wordpress.org&utm_medium=referral&utm_campaign=plugin_directory&utm_content=advanced_custom_fields\">WP Engine</a>\";s:12:\"contributors\";a:9:{s:15:\"deliciousbrains\";a:3:{s:7:\"profile\";s:47:\"https://profiles.wordpress.org/deliciousbrains/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/c55b6dfd266f44f127170d402922e485?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"Delicious Brains\";}s:8:\"wpengine\";a:3:{s:7:\"profile\";s:40:\"https://profiles.wordpress.org/wpengine/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/6d44461b684d2f3d8f6fcf3d657cb889?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:9:\"WP Engine\";}s:12:\"elliotcondon\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/elliotcondon/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/533079e82e526367047100d8019cb9a7?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Elliot Condon\";}s:8:\"mattshaw\";a:3:{s:7:\"profile\";s:40:\"https://profiles.wordpress.org/mattshaw/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/c0ec3df5b2d5cf25ca1ab1fc3fdbe270?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:9:\"Matt Shaw\";}s:7:\"lgladdy\";a:3:{s:7:\"profile\";s:39:\"https://profiles.wordpress.org/lgladdy/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/1c126b5df1afc631b50bae0dda8094d7?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:11:\"Liam Gladdy\";}s:5:\"antpb\";a:3:{s:7:\"profile\";s:37:\"https://profiles.wordpress.org/antpb/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/9fe91e0d637984c9d4bb6d2f27cd7eb4?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"Anthony Burchell\";}s:14:\"johnstonphilip\";a:3:{s:7:\"profile\";s:46:\"https://profiles.wordpress.org/johnstonphilip/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/459d1a78b2c7c46729a175c372a9be4f?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Phil Johnston\";}s:12:\"dalewilliams\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/dalewilliams/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/c0528da391a7f8b5a403404224347421?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Dale Williams\";}s:12:\"polevaultweb\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/polevaultweb/\";s:6:\"avatar\";s:88:\"https://secure.gravatar.com/avatar/920dd5ed3b01d7185cc421e15e75ef07?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:12:\"Iain Poulson\";}}s:8:\"requires\";s:3:\"6.2\";s:12:\"requires_php\";s:3:\"7.4\";s:6:\"tested\";s:5:\"6.8.3\";s:5:\"added\";s:10:\"2025-10-16\";s:12:\"last_updated\";s:10:\"2025-10-29\";s:11:\"description\";s:5270:\"<p>Advanced Custom Fields (ACF®) turns WordPress sites into a fully-fledged content management system by giving you all the tools to do more with your data.</p>\n\n<p>Use the ACF plugin to take full control of your WordPress edit screens, custom field data, and more.</p>\n\n<p>https://www.youtube.com/watch?v=9C6_roqghZQ&rel=0</p>\n\n<p><strong>Add fields on demand.</strong></p>\n<p>The ACF field builder allows you to quickly and easily add fields to WP edit screens with only the click of a few buttons! Whether it\'s something simple like adding an “author” field to a book review post, or something more complex like the structured data needs of an ecommerce site or marketplace, ACF makes adding fields to your content model easy.</p>\n\n<p><strong>Add them anywhere.</strong></p>\n<p>Fields can be added all over WordPress including posts, pages, users, taxonomy terms, media, comments and even custom options pages! It couldn\'t be simpler to bring structure to the WordPress content creation experience.</p>\n\n<p><strong>Show them everywhere.</strong></p>\n<p>Load and display your custom field values in any theme template file with our hassle-free, developer friendly functions! Whether you need to display a single value or generate content based on a more complex query, the out-of-the-box functions of ACF make templating a dream for developers of all levels of experience.</p>\n\n<p><strong>Any Content, Fast.</strong></p>\n<p>Turning WordPress into a true content management system is not just about custom fields. Creating new custom post types and taxonomies is an essential part of building custom WordPress sites. Registering post types and taxonomies is now possible right in the ACF UI, speeding up the content modeling workflow without the need to touch code or use another plugin.</p>\n\n<p><strong>Simply beautiful and intentionally accessible.</strong></p>\n<p>For content creators and those tasked with data entry, the field user experience is as intuitive as they could desire while fitting neatly into the native WordPress experience. Accessibility standards are regularly reviewed and applied, ensuring ACF is able to empower as close to anyone as possible.</p>\n\n<p><strong>Documentation and developer guides.</strong></p>\n<p>Over 10 plus years of vibrant community contribution alongside an ongoing commitment to clear documentation means that you\'ll be able to find the guidance you need to build what you want.</p>\n\n<h4>Features</h4>\n<ul>\n<li>Simple & Intuitive</li>\n<li>Powerful Functions</li>\n<li>Over 30 Field Types</li>\n<li>Extensive Documentation</li>\n<li>Millions of Users</li>\n</ul>\n\n<h4>Links</h4>\n<ul>\n<li><a href=\"https://www.advancedcustomfields.com/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Website\">Website</a></li>\n<li><a href=\"https://www.advancedcustomfields.com/resources/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Website\">Documentation</a></li>\n<li><a href=\"https://support.advancedcustomfields.com\">Support</a></li>\n<li><a href=\"https://www.advancedcustomfields.com/pro/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">ACF PRO</a></li>\n</ul>\n\n<h4>PRO</h4>\n<p>The Advanced Custom Fields plugin is also available in a professional version which includes more fields, more functionality, and more flexibility. The ACF PRO plugin features:</p>\n\n<ul>\n<li>The <a href=\"https://www.advancedcustomfields.com/resources/repeater/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">Repeater Field</a> allows you to create a set of sub fields which can be repeated again, and again, and again.</li>\n<li><a href=\"https://www.advancedcustomfields.com/resources/blocks/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">ACF Blocks</a>, a powerful PHP-based framework for developing custom block types for the WordPress Block Editor (aka Gutenberg).</li>\n<li>Define, create, and manage content with the <a href=\"https://www.advancedcustomfields.com/resources/flexible-content/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">Flexible Content Field</a>, which provides for multiple layout and sub field options.</li>\n<li>Use the <a href=\"https://www.advancedcustomfields.com/resources/options-page/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">Options Page</a> feature to add custom admin pages to edit ACF fields.</li>\n<li>Build fully customisable image galleries with the <a href=\"https://www.advancedcustomfields.com/resources/gallery/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">Gallery Field</a>.</li>\n<li>Unlock a more efficient workflow for managing field settings by reusing existing fields and field groups on demand with the <a href=\"https://www.advancedcustomfields.com/resources/clone/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">Clone Field</a>.</li>\n</ul>\n\n<p><a href=\"https://www.advancedcustomfields.com/pro/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Pro%20Upgrade\">Upgrade to ACF PRO</a></p>\";s:12:\"installation\";s:649:\"<p>From your WordPress dashboard</p>\n\n<ol>\n<li><strong>Visit</strong> Plugins > Add New</li>\n<li><strong>Search</strong> for \"Advanced Custom Fields\" or “ACF”</li>\n<li><strong>Install and Activate</strong> Advanced Custom Fields from your Plugins page</li>\n<li><strong>Click</strong> on the new menu item \"ACF\" and create your first custom field group, or register a custom post type or taxonomy.</li>\n<li><strong>Read</strong> the documentation to <a href=\"https://www.advancedcustomfields.com/resources/getting-started-with-acf/?utm_source=wordpress.org&utm_medium=free%20plugin%20listing&utm_campaign=ACF%20Website\">get started</a></li>\n</ol>\";s:9:\"changelog\";s:3961:\"<h4>6.6.2</h4>\n<p><em>Release Date 29th October 2025</em></p>\n\n<ul>\n<li>Enhancement - Added a new <code>convert_field_name_to_lowercase</code> JS filter to allow uppercase letters in ACF field names</li>\n<li>Enhancement - The form for V3 Blocks can now be optionally hidden from the sidebar via a new <code>hideFieldsInSidebar</code> setting in block.json</li>\n<li>Enhancement - V3 Blocks now display an \"Open Expanded Editor\" button in the sidebar for easier access to the full edit form</li>\n<li>Fix - The buttons to reorder ACF metaboxes are no longer hidden for metaboxes in the block editor sidebar</li>\n<li>Fix - V3 Blocks now display a fallback message when the block preview can\'t be rendered due to invalid HTML being used in field values</li>\n<li>Fix - V3 Blocks no longer show a loading spinner when preloaded</li>\n<li>Fix - V3 Blocks now save default field values even if the block wasn\'t interacted with before saving</li>\n<li>Fix - Pressing CMD/CTRL + Z no longer causes the fields to disappear in V3 Blocks</li>\n<li>Fix - The form for V3 Blocks now opens on the left side in RTL languages</li>\n</ul>\n\n<h4>6.6.1</h4>\n<p><em>Release Date 16th October 2025</em></p>\n\n<ul>\n<li>Fix - The Color Picker palette now displays correctly with a larger number of custom palette colors</li>\n<li>Fix - The WYSIWYG field no longer displays an extra textarea in ACF Blocks</li>\n<li>Fix - The type signature of the ACF Blocks render function now matches prior to 6.6, resolving potential type hinting errors</li>\n<li>Fix - V3 Blocks now correctly update the block preview when changing text controls</li>\n<li>Fix - V3 Blocks now work correctly in the Widget block editor</li>\n<li>Fix - V3 Blocks no longer render an extra hidden div into the block editor</li>\n<li>Fix - Fields on V3 blocks now consistently render properly when switching between “Post” and “Block” view in the sidebar</li>\n</ul>\n\n<h4>6.6.0</h4>\n<p><em>Release Date 7th October 2025</em></p>\n\n<ul>\n<li><a href=\"https://www.advancedcustomfields.com/blog/acf-6-6-released/\">View Release Post</a></li>\n<li>New - ACF Blocks Version 3 supports WordPress Block API Version 3</li>\n<li>New - ACF now requires WordPress version 6.2 or newer</li>\n<li>Enhancement - Field Groups can now have a separate Display Title</li>\n<li>Enhancement - Accessibility improvements for button groups, checkbox, radio, and image field types</li>\n<li>Enhancement - Color Picker field can now use a custom palette or use theme.json colors as the palette</li>\n<li>Enhancement - ACF admin notices now use WordPress core styles again</li>\n<li>Enhancement - The Flexible Content “Delete Layout” and “Rename Layout” modals now display correctly on mobile</li>\n<li>Fix - Blocks V3: You can now edit ACF blocks in Edit mode inside WP Core\'s pattern editor</li>\n<li>Fix - Blocks V3: Validation errors now first appear after you click \"Save/publish\", as opposed to immediately, while you are typing into a field for the first time</li>\n<li>Fix - Blocks V3: After fixing a field validation error it shows as fixed immediately as opposed to needing to click out of the block and back into it</li>\n<li>Fix - Blocks V3: Blocks with radio buttons no longer affect each other\'s field values</li>\n<li>Fix - Blocks V3: Blocks with required radio buttons now validate correctly</li>\n<li>Fix - Blocks V3: ACF field validation now works in the Site Editor</li>\n<li>Fix - Blocks V3: WYSIWYG fields are no longer affected by typing into other blocks</li>\n<li>Fix - New field names are lowercase only</li>\n<li>Fix - Icon Picker now enforces required validation</li>\n<li>Fix - Calls to jQuery’s deprecated focus function have been updated to use the trigger function</li>\n<li>Fix - Layouts inside cloned Flexible Content fields can now be disabled and renamed</li>\n<li>i18n - Updated PRO Japanese translations (props danielkun)</li>\n</ul>\n\n<p><a href=\"https://www.advancedcustomfields.com/changelog/\">View the full changelog</a></p>\";s:14:\"upgrade_notice\";s:0:\"\";s:5:\"icons\";a:1:{s:7:\"default\";s:64:\"https://connect.advancedcustomfields.com/assets/icon-256x256.png\";}s:7:\"banners\";a:2:{s:3:\"low\";s:66:\"https://connect.advancedcustomfields.com/assets/banner-772x250.jpg\";s:4:\"high\";s:67:\"https://connect.advancedcustomfields.com/assets/banner-1544x500.jpg\";}s:8:\"versions\";a:156:{i:0;s:11:\"6.7.0-beta1\";i:1;s:5:\"6.6.1\";i:2;s:5:\"6.6.0\";i:3;s:5:\"6.5.1\";i:4;s:7:\"6.5.0.1\";i:5;s:5:\"6.5.0\";i:6;s:9:\"6.5.0-RC1\";i:7;s:5:\"6.4.3\";i:8;s:5:\"6.4.2\";i:9;s:5:\"6.4.1\";i:10;s:7:\"6.4.0.1\";i:11;s:5:\"6.4.0\";i:12;s:9:\"6.4.0-RC1\";i:13;s:6:\"6.3.12\";i:14;s:6:\"6.3.11\";i:15;s:6:\"6.3.10\";i:16;s:5:\"6.3.9\";i:17;s:5:\"6.3.8\";i:18;s:5:\"6.3.7\";i:19;s:5:\"6.3.6\";i:20;s:5:\"6.3.5\";i:21;s:5:\"6.3.4\";i:22;s:5:\"6.3.3\";i:23;s:7:\"6.3.2.1\";i:24;s:5:\"6.3.2\";i:25;s:7:\"6.3.1.2\";i:26;s:7:\"6.3.1.1\";i:27;s:5:\"6.3.1\";i:28;s:7:\"6.3.0.1\";i:29;s:5:\"6.3.0\";i:30;s:11:\"6.3.0-beta1\";i:31;s:6:\"6.2.10\";i:32;s:5:\"