:5:\"12114\";s:7:\"created\";s:19:\"2022-08-01 11:13:01\";s:7:\"updated\";s:19:\"2022-08-01 11:51:54\";}i:3;O:8:\"stdClass\":9:{s:5:\"value\";s:0:\"\";s:7:\"plan_id\";s:5:\"18231\";s:9:\"plugin_id\";s:4:\"7180\";s:5:\"title\";s:17:\"Shortcode Creator\";s:11:\"description\";s:75:\"A powerful editor which allows creating custom shortcodes with HTML and PHP\";s:11:\"is_featured\";b:1;s:2:\"id\";s:5:\"12115\";s:7:\"created\";s:19:\"2022-08-01 11:13:07\";s:7:\"updated\";s:19:\"2022-08-01 11:52:16\";}}}}s:7:\"reviews\";a:5:{i:0;O:8:\"stdClass\":22:{s:5:\"first\";N;s:4:\"last\";N;s:5:\"email\";N;s:9:\"plugin_id\";s:4:\"7180\";s:11:\"external_id\";N;s:7:\"user_id\";N;s:4:\"rate\";i:100;s:5:\"title\";s:18:\"Highly recommended\";s:4:\"text\";s:120:\"No problems, only value… I like it, and as it adds many functions, it keeps my plugin number down. Highly recommended.\";s:4:\"name\";s:18:\"Ambassador Rodgers\";s:9:\"job_title\";N;s:7:\"company\";N;s:11:\"company_url\";N;s:7:\"picture\";s:101:\"https://s3-us-west-2.amazonaws.com/freemius/plugins/7180/reviews/6750d41f65463b2c896d5733d602a96d.png\";s:11:\"profile_url\";N;s:10:\"license_id\";N;s:11:\"is_verified\";b:0;s:11:\"is_featured\";b:1;s:11:\"environment\";i:0;s:2:\"id\";s:5:\"10304\";s:7:\"created\";s:19:\"2022-08-01 09:55:30\";s:7:\"updated\";s:19:\"2022-08-01 10:00:09\";}i:1;O:8:\"stdClass\":22:{s:5:\"first\";N;s:4:\"last\";N;s:5:\"email\";N;s:9:\"plugin_id\";s:4:\"7180\";s:11:\"external_id\";N;s:7:\"user_id\";N;s:4:\"rate\";i:100;s:5:\"title\";s:13:\"Simply superb\";s:4:\"text\";s:136:\"I am using this plugin for 2 years. Simply superb. Great coding. Anyone can design the pages with this plugin without any coding skills.\";s:4:\"name\";s:23:\"Satish Kumar Ithamsetty\";s:9:\"job_title\";N;s:7:\"company\";N;s:11:\"company_url\";N;s:7:\"picture\";s:101:\"https://s3-us-west-2.amazonaws.com/freemius/plugins/7180/reviews/2e6e0bc80df96eef7a0b6115ed81db93.png\";s:11:\"profile_url\";N;s:10:\"license_id\";N;s:11:\"is_verified\";b:0;s:11:\"is_featured\";b:1;s:11:\"environment\";i:0;s:2:\"id\";s:5:\"10303\";s:7:\"created\";s:19:\"2022-08-01 09:54:08\";s:7:\"updated\";s:19:\"2022-08-01 09:59:02\";}i:2;O:8:\"stdClass\":22:{s:5:\"first\";N;s:4:\"last\";N;s:5:\"email\";N;s:9:\"plugin_id\";s:4:\"7180\";s:11:\"external_id\";N;s:7:\"user_id\";N;s:4:\"rate\";i:100;s:5:\"title\";s:11:\"I recommend\";s:4:\"text\";s:122:\"I recommend it to everyone who is serious of content creation. It has an intuitive interface and it is really easy to use.\";s:4:\"name\";s:13:\"Duane Bentzen\";s:9:\"job_title\";N;s:7:\"company\";N;s:11:\"company_url\";N;s:7:\"picture\";s:102:\"https://s3-us-west-2.amazonaws.com/freemius/plugins/7180/reviews/46a0464ae992a9bd86878fb96cdc4187.jpeg\";s:11:\"profile_url\";N;s:10:\"license_id\";N;s:11:\"is_verified\";b:0;s:11:\"is_featured\";b:1;s:11:\"environment\";i:0;s:2:\"id\";s:5:\"10302\";s:7:\"created\";s:19:\"2022-08-01 09:52:21\";s:7:\"updated\";s:19:\"2022-08-01 09:58:52\";}i:3;O:8:\"stdClass\":22:{s:5:\"first\";N;s:4:\"last\";N;s:5:\"email\";N;s:9:\"plugin_id\";s:4:\"7180\";s:11:\"external_id\";s:8:\"15813589\";s:7:\"user_id\";N;s:4:\"rate\";i:100;s:5:\"title\";s:15:\"Perfect plugin!\";s:4:\"text\";s:394:\"<p>I love being able to include a ready-to-use short code instead of diluting the script with long snippets of code. Its honestly easy enough to use even if you do not have a coding background. For example, I can create a form from a different plugin, and it generates a shortcode. Now, I copy/paste in the exact place on a different page where I want it. Makes it 20000000000 times easier!</p>\";s:4:\"name\";s:12:\"mhilldigital\";s:9:\"job_title\";N;s:7:\"company\";N;s:11:\"company_url\";N;s:7:\"picture\";s:85:\"https://secure.gravatar.com/avatar/6e98b71c03389fcfd6292663ff438629?s=100&d=retro&r=g\";s:11:\"profile_url\";s:44:\"https://profiles.wordpress.org/mhilldigital/\";s:10:\"license_id\";N;s:11:\"is_verified\";b:0;s:11:\"is_featured\";b:1;s:11:\"environment\";i:0;s:2:\"id\";s:5:\"10401\";s:7:\"created\";s:19:\"2022-07-14 06:07:50\";s:7:\"updated\";s:19:\"2022-08-14 06:08:04\";}i:4;O:8:\"stdClass\":22:{s:5:\"first\";N;s:4:\"last\";N;s:5:\"email\";N;s:9:\"plugin_id\";s:4:\"7180\";s:11:\"external_id\";s:8:\"15762704\";s:7:\"user_id\";N;s:4:\"rate\";i:100;s:5:\"title\";s:24:\"Great plugin! Keep it up\";s:4:\"text\";s:124:\"<p>This plugin is really great and would certainly satiate your needs. Give a trial and thank me later.</p> <p>Peace out</p>\";s:4:\"name\";s:8:\"survzeal\";s:9:\"job_title\";N;s:7:\"company\";N;s:11:\"company_url\";N;s:7:\"picture\";s:85:\"https://secure.gravatar.com/avatar/90758ee441e082def2c3a41f309c58a1?s=100&d=retro&r=g\";s:11:\"profile_url\";s:40:\"https://profiles.wordpress.org/survzeal/\";s:10:\"license_id\";N;s:11:\"is_verified\";b:0;s:11:\"is_featured\";b:1;s:11:\"environment\";i:0;s:2:\"id\";s:5:\"10402\";s:7:\"created\";s:19:\"2022-06-23 06:07:51\";s:7:\"updated\";s:19:\"2022-08-14 06:08:04\";}}s:15:\"active_installs\";i:500000;s:9:\"downloads\";i:23682510;s:29:\"all_plans_single_site_pricing\";O:8:\"stdClass\":2:{s:5:\"11697\";O:8:\"stdClass\":3:{s:13:\"monthly_price\";O:8:\"stdClass\":3:{s:3:\"usd\";i:0;s:3:\"gbp\";i:0;s:3:\"eur\";i:0;}s:12:\"annual_price\";O:8:\"stdClass\":3:{s:3:\"usd\";i:0;s:3:\"gbp\";i:0;s:3:\"eur\";i:0;}s:14:\"lifetime_price\";O:8:\"stdClass\":3:{s:3:\"usd\";i:0;s:3:\"gbp\";i:0;s:3:\"eur\";i:0;}}s:5:\"18231\";O:8:\"stdClass\":3:{s:13:\"monthly_price\";O:8:\"stdClass\":3:{s:3:\"usd\";d:4.0833333333333;s:3:\"gbp\";i:0;s:3:\"eur\";i:0;}s:12:\"annual_price\";O:8:\"stdClass\":3:{s:3:\"usd\";i:49;s:3:\"gbp\";i:0;s:3:\"eur\";i:0;}s:14:\"lifetime_price\";O:8:\"stdClass\":3:{s:3:\"usd\";i:149;s:3:\"gbp\";i:0;s:3:\"eur\";i:0;}}}s:12:\"checkout_url\";s:29:\"https://checkout.freemius.com\";s:18:\"fs_wp_endpoint_url\";s:23:\"https://wp.freemius.com\";s:10:\"trial_mode\";b:0;s:14:\"trial_utilized\";b:0;s:23:\"skip_directly_to_paypal\";b:0;s:19:\"is_paypal_supported\";b:1;}s:7:\"created\";i:1763567607